     8→
     9→  const handleSubmit = async (e) => {
    10→    e.preventDefault();
    11→    setLoading(true);
    12→    setFormError(validateForm(formValue));
    13→    if (Object.keys(validateForm(formValue)).length > 0) {
    14→      setLoading(false);
    15→      return null;
    16→    } else {
    17→      setSubmit(true);
    18→      setFormValue({ email: "" });
